// Keep just the fields we need for the GoToWebinar match, clean and copy-ready.
return $input.all().map((it) => {
  const c = it.json;
  return { json: {
    campaign_key: c.Id,
    name: c.Name || null,
    type: c.Type || null,
    status: c.Status || null,
    start_date: c.StartDate || null,
    end_date: c.EndDate || null
  }};
});
